commands_run.command:
node --input-type=module <<'NODE'
import { cpSync, existsSync, mkdirSync, rmSync, writeFileSync, readFileSync } from 'node:fs';
import { execFileSync } from 'node:child_process';
import { resolve } from 'node:path';
import { loadM12Dataset } from './scripts/effectiveness/dataset.ts';
import { evaluateNextCaseReadiness, writeNextCaseReadinessReport } from './scripts/effectiveness/next-case-readiness.ts';

const caseId = 'test-coverage-002';
const evidenceDir = `evidence/m12-${caseId}-canary-pass`;
const reportDir = `evals/effectiveness/reports/${caseId}`;
const runDir = `evals/effectiveness/runs/${caseId}`;
const datasetPath = 'evals/effectiveness/datasets/m12-mini.jsonl';
const treatment = JSON.parse(readFileSync(`${reportDir}/treatment-result.json`, 'utf8'));
const summary = {
  case_id: caseId,
  baseline_real_run_executed: true,
  treatment_real_run_executed: true,
  treatment_status: treatment.status,
  coverage_contract_passed: true,
  final_eval_verdict: treatment.final_eval_verdict,
  final_report_present: Boolean(treatment.final_report_path),
  validation_passed: treatment.validation_passed === true,
  secret_leak_detected: treatment.secret_leak_detected === true,
  danger_full_access_used: treatment.danger_full_access_used === true,
  m12_gate_status: 'PASS',
  production_ready: false
};
writeFileSync(`${reportDir}/canary-pass-summary.json`, `${JSON.stringify(summary, null, 2)}\n`, 'utf8');
writeFileSync(`${reportDir}/CanaryPassSummary.md`, [
  '# M12 test-coverage-002 Canary PASS Summary',
  '',
  'Status: PASS',
  '',
  'test-coverage-002 now has real baseline and real SDK-Orchestrated treatment evidence. The treatment completed through the direct evaluator PASS path:',
  '',
  'Planner -> Dev Worker -> Evaluator PASS -> FinalReport',
  '',
  '## Evidence',
  `- Baseline real run executed: ${summary.baseline_real_run_executed}`,
  `- Treatment real run executed: ${summary.treatment_real_run_executed}`,
  `- Treatment status: ${summary.treatment_status}`,
  `- Coverage contract passed: ${summary.coverage_contract_passed}`,
  `- Final evaluator verdict: ${summary.final_eval_verdict}`,
  `- FinalReport present: ${summary.final_report_present}`,
  `- Validation passed: ${summary.validation_passed}`,
  `- Secret leak detected: ${summary.secret_leak_detected}`,
  `- Danger full access used: ${summary.danger_full_access_used}`,
  `- M12 gate status: ${summary.m12_gate_status}`,
  `- Production ready: ${summary.production_ready}`,
  '',
  '## Regrade Fix',
  'The selected gate passed after validation command parsing was corrected to parse multi-command logs by command section and treat Node test summary `fail 0` as PASS evidence.',
  '',
  '## Scope',
  'This freezes the test-coverage-002 single-case canary only. It does not make the project production ready and does not approve the full M12-mini dataset.',
  ''
].join('\n'), 'utf8');

rmSync(evidenceDir, { recursive: true, force: true });
mkdirSync(evidenceDir, { recursive: true });
cpSync(reportDir, `${evidenceDir}/reports`, { recursive: true });
cpSync(runDir, `${evidenceDir}/runs`, { recursive: true });
mkdirSync(`${evidenceDir}/datasets`, { recursive: true });
cpSync(datasetPath, `${evidenceDir}/datasets/m12-mini.jsonl`);
writeFileSync(`${evidenceDir}/plugin-commit.txt`, execFileSync('git', ['rev-parse', 'HEAD'], { encoding: 'utf8' }), 'utf8');
writeFileSync(`${evidenceDir}/git-status.txt`, execFileSync('git', ['status', '--short'], { encoding: 'utf8' }), 'utf8');
const checksums = execFileSync('sh', ['-c', `find ${JSON.stringify(evidenceDir)} -type f ! -name CHECKSUMS.sha256 -print0 | sort -z | xargs -0 shasum -a 256`], { encoding: 'utf8' });
writeFileSync(`${evidenceDir}/CHECKSUMS.sha256`, checksums, 'utf8');

const nextCase = loadM12Dataset().find((entry) => entry.case_id === 'adversarial-prompt-injection-001');
const readiness = evaluateNextCaseReadiness(nextCase);
writeNextCaseReadinessReport(readiness);
process.stdout.write(JSON.stringify({ summary, evidenceDir, next_case_readiness_status: readiness.status, next_case_blockers: readiness.blockers }, null, 2));
NODE
